insert into public.study_questions (id, subject_id, topic_id, level, statement, options, correct_index, explanation, sort_order) values
  (101, 'administracao-publica', 'administracao-publica-planejamento-organizacao-direcao-e-controle', 'Médio', 'Em uma secretaria municipal, o gestor definiu metas trimestrais, distribuiu tarefas entre equipes, acompanhou indicadores e corrigiu desvios de execução. As ações descritas correspondem, respectivamente, às funções administrativas de', '["planejamento, organização, direção e controle.","organização, planejamento, comando e avaliação.","previsão, liderança, execução e auditoria.","coordenação, direção, comando e responsabilização."]'::jsonb, 0, 'O enunciado segue a sequência clássica das funções administrativas: planejar metas, organizar recursos, dirigir pessoas e controlar resultados.', 1),
  (102, 'administracao-publica', 'administracao-publica-gestao-por-processos', 'Médio', 'Ao mapear o fluxo de atendimento ao cidadão, a equipe identificou retrabalho, gargalos e etapas sem valor agregado. A medida mais aderente à gestão por processos é', '["substituir o fluxo atual por decisões informais das chefias.","eliminar a necessidade de indicadores para ganhar agilidade.","redesenhar o processo com foco em padronização, eficiência e entrega ao usuário.","aumentar o número de assinaturas obrigatórias em todas as etapas."]'::jsonb, 2, 'Na gestão por processos, o foco está em fluxo, melhoria contínua, eliminação de desperdícios e geração de valor ao usuário final.', 2),
  (103, 'administracao-publica', 'administracao-publica-governanca-e-accountability', 'Difícil', 'No setor público, a accountability está diretamente relacionada à', '["dispensa de prestação de contas quando há delegação de competência.","autonomia absoluta do gestor para decidir sem controle externo.","obrigação de prestar contas, justificar resultados e sujeitar-se à responsabilização.","substituição dos controles institucionais por confiança pessoal na chefia."]'::jsonb, 2, 'Accountability envolve transparência, prestação de contas e possibilidade de responsabilização pelos atos e resultados da gestão.', 3),
  (104, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-principios-da-administracao-publica', 'Fácil', 'Quando a administração divulga critérios objetivos para seleção de fornecedores e veda favorecimentos pessoais, ela concretiza principalmente os princípios da', '["moralidade e impessoalidade.","publicidade e supremacia privada.","discricionariedade e autotutela.","hierarquia e especialidade."]'::jsonb, 0, 'A vedação de favorecimentos pessoais se conecta à impessoalidade, enquanto a conduta ética e proba se relaciona à moralidade administrativa.', 4),
  (105, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-atos-administrativos', 'Médio', 'Um servidor praticou ato administrativo com finalidade diversa da prevista em lei, embora formalmente competente. Nessa hipótese, o vício recai sobre o elemento', '["forma.","motivo.","objeto.","finalidade."]'::jsonb, 3, 'Desvio de finalidade ocorre quando o agente busca fim diverso do previsto em lei, comprometendo o elemento finalidade do ato administrativo.', 5),
  (106, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-lei-n-14-133-2021', 'Difícil', 'De acordo com a lógica da Lei nº 14.133/2021, a fase preparatória da contratação deve', '["ser dispensada quando o objeto for rotineiro.","concentrar estudos técnicos, definição da necessidade e planejamento da contratação.","ocorrer apenas após a assinatura do contrato administrativo.","limitar-se à indicação verbal do setor requisitante."]'::jsonb, 1, 'A nova lei reforça o planejamento como eixo da contratação pública, incluindo estudos técnicos, gestão de riscos e definição adequada do objeto.', 6),
  (107, 'portugues', 'portugues-sentido-vocabular-no-contexto', 'Fácil', 'No período “a revisão cuidadosa evita retrabalho”, o verbo “evita” expressa ideia de', '["causa.","prevenção.","comparação.","concessão."]'::jsonb, 1, 'No contexto, “evitar” significa impedir previamente ou prevenir a ocorrência de algo.', 7),
  (108, 'portugues', 'portugues-concordancia-verbal', 'Médio', 'Assinale a alternativa em que a concordância verbal está de acordo com a norma-padrão.', '["Houveram atrasos na entrega dos relatórios finais.","Fazem dois anos que o setor utiliza esse sistema.","Existe medidas simples para reduzir falhas operacionais.","Deve haver soluções viáveis para o problema apresentado."]'::jsonb, 3, 'Com o verbo “haver” no sentido de existir, a construção correta é impessoal. Na locução, mantém-se “deve haver”.', 8),
  (109, 'portugues', 'portugues-oracoes-subordinadas', 'Difícil', 'No trecho “A equipe confirmou que o cronograma precisaria ser revisto”, a oração destacada exerce função de', '["adjunto adnominal.","objeto direto.","predicativo do sujeito.","aposto explicativo."]'::jsonb, 1, 'A oração introduzida por “que” completa o sentido do verbo “confirmou”, funcionando como oração subordinada substantiva objetiva direta.', 9),
  (110, 'informatica', 'informatica-microsoft-excel', 'Fácil', 'No Microsoft Excel, para somar os valores contidos nas células B2 até B10, a fórmula correta é', '["=SOMA(B2:B10)","=SOMAR(B2;B10)","=MEDIA(B2:B10)","=ADICAO(B2..B10)"]'::jsonb, 0, 'Em Excel em português, a função padrão para soma é =SOMA(intervalo).', 10),
  (111, 'informatica', 'informatica-windows-e-gerenciamento-de-arquivos', 'Médio', 'Ao utilizar o Explorador de Arquivos no Windows, o usuário deseja renomear rapidamente um arquivo já selecionado, sem abrir menus contextuais. O atalho mais usual para essa ação é', '["F2.","F5.","Ctrl+R.","Alt+F4."]'::jsonb, 0, 'No Windows, F2 é o atalho tradicional para renomear o item selecionado.', 11),
  (112, 'informatica', 'informatica-correio-eletronico-e-boas-praticas', 'Médio', 'Em ambiente corporativo, uma boa prática de segurança no uso de e-mail é', '["abrir anexos de remetentes desconhecidos para verificar o conteúdo.","reutilizar a mesma senha em serviços diferentes para facilitar o acesso.","confirmar links suspeitos e remetentes antes de clicar ou baixar arquivos.","desativar filtros antispam para evitar bloqueio de mensagens legítimas."]'::jsonb, 2, 'A conferência de remetente, link e contexto da mensagem reduz risco de phishing e instalação de arquivos maliciosos.', 12),
  (113, 'raciocinio-logico', 'raciocinio-logico-negacao-de-condicional', 'Médio', 'A negação da proposição “Se o processo foi instruído corretamente, então o pagamento será liberado” é', '["O processo foi instruído corretamente e o pagamento não será liberado.","O processo não foi instruído corretamente e o pagamento será liberado.","Se o pagamento não for liberado, então o processo não foi instruído corretamente.","O processo foi instruído corretamente ou o pagamento não será liberado."]'::jsonb, 0, 'A negação de uma condicional p → q é p e não q.', 13),
  (114, 'raciocinio-logico', 'raciocinio-logico-porcentagem', 'Fácil', 'Um servidor executou 18 de 24 tarefas previstas para a semana. O percentual de tarefas concluídas foi de', '["65%.","70%.","75%.","80%."]'::jsonb, 2, '18 ÷ 24 = 0,75, o que corresponde a 75%.', 14),
  (115, 'raciocinio-logico', 'raciocinio-logico-sequencias', 'Difícil', 'Observe a sequência numérica: 3, 8, 18, 38, ... Mantido o padrão, o próximo termo é', '["68.","76.","78.","80."]'::jsonb, 2, 'A sequência dobra o termo anterior e soma 2: 3→8, 8→18, 18→38, então 38×2+2 = 78.', 15),
  (116, 'administracao-publica', 'administracao-publica-gestao-estrategica', 'Médio', 'Em um órgão municipal, a definição de objetivos de longo prazo, indicadores e iniciativas prioritárias está mais diretamente relacionada ao conceito de', '["planejamento estratégico.","controle corretivo.","departamentalização funcional.","descentralização patrimonial."]'::jsonb, 0, 'Planejamento estratégico orienta objetivos de longo prazo, prioridades institucionais e indicadores de acompanhamento.', 16),
  (117, 'administracao-publica', 'administracao-publica-estrutura-organizacional', 'Fácil', 'A divisão do trabalho por áreas como finanças, compras e recursos humanos caracteriza a departamentalização', '["por produto.","funcional.","geográfica.","por clientela."]'::jsonb, 1, 'Na departamentalização funcional, as unidades são agrupadas segundo funções ou especialidades semelhantes.', 17),
  (118, 'administracao-publica', 'administracao-publica-qualidade-no-servico-publico', 'Médio', 'Uma prática coerente com a gestão da qualidade no serviço público é', '["avaliar resultados apenas pela percepção da chefia imediata.","padronizar rotinas, monitorar falhas e buscar melhoria contínua.","eliminar canais de feedback para reduzir demandas do usuário.","substituir indicadores por decisões exclusivamente intuitivas."]'::jsonb, 1, 'Qualidade envolve padronização, acompanhamento de desempenho, foco no usuário e melhoria contínua.', 18),
  (119, 'administracao-publica', 'administracao-publica-tipos-de-planejamento', 'Médio', 'O planejamento tático distingue-se do estratégico porque, em regra,', '["abrange toda a organização e horizonte mais amplo.","traduz diretrizes gerais em metas setoriais de médio prazo.","se restringe a rotinas diárias e tarefas operacionais.","dispensa definição de recursos e responsáveis."]'::jsonb, 1, 'O planejamento tático converte diretrizes estratégicas em ações e metas das áreas ou unidades.', 19),
  (120, 'administracao-publica', 'administracao-publica-governabilidade-e-governanca', 'Difícil', 'Em análise organizacional, governança pública e governabilidade diferenciam-se porque a primeira enfatiza', '["mecanismos de direção, controle e integridade, enquanto a segunda se relaciona à capacidade política de implementar decisões.","a hierarquia informal, enquanto a segunda trata exclusivamente de orçamento.","a execução rotineira de tarefas, enquanto a segunda cuida apenas de tecnologia.","a autonomia privada, enquanto a segunda elimina controles institucionais."]'::jsonb, 0, 'Governança trata de estruturas, controles e direção institucional; governabilidade liga-se à capacidade de articulação e implementação.', 20),
  (121, 'administracao-publica', 'administracao-publica-servicos-publicos', 'Médio', 'Ao reorganizar o atendimento presencial para reduzir filas e ampliar o acesso do cidadão, a administração atua com foco principal na', '["continuidade e adequação do serviço público.","supremacia do interesse do servidor.","revogação automática de atos administrativos.","privatização compulsória da atividade administrativa."]'::jsonb, 0, 'A melhoria do atendimento e do acesso do usuário está ligada à adequada prestação e continuidade dos serviços públicos.', 21),
  (122, 'administracao-publica', 'administracao-publica-indicadores-de-desempenho', 'Médio', 'Um indicador que mede o percentual de processos concluídos dentro do prazo legal avalia principalmente', '["tempestividade.","amplitude hierárquica.","centralização.","especialização vertical."]'::jsonb, 0, 'Tempestividade refere-se ao cumprimento de prazos e à entrega oportuna dos resultados.', 22),
  (123, 'administracao-publica', 'administracao-publica-lideranca-e-direcao', 'Fácil', 'No exercício da função de direção, o gestor público atua principalmente ao', '["motivar equipes, orientar execução e comunicar prioridades.","definir apenas a estrutura formal do órgão.","substituir o controle por confiança irrestrita.","eliminar a necessidade de metas institucionais."]'::jsonb, 0, 'Direção envolve liderança, comunicação, orientação das pessoas e alinhamento da execução às metas.', 23),
  (124, 'administracao-publica', 'administracao-publica-mapeamento-de-processos', 'Difícil', 'Em um redesenho de processo, a identificação de entradas, atividades, saídas e responsáveis permite principalmente', '["formalizar gargalos como etapa obrigatória.","visualizar o fluxo de trabalho e atacar pontos críticos com maior precisão.","eliminar a necessidade de padronização documental.","substituir metas por relatos subjetivos dos usuários."]'::jsonb, 1, 'O mapeamento explicita o fluxo e facilita detectar gargalos, responsabilidades e oportunidades de melhoria.', 24),
  (125, 'administracao-publica', 'administracao-publica-controle-administrativo', 'Médio', 'Quando a chefia compara o resultado alcançado com a meta prevista e adota ações corretivas, está exercendo a função de', '["organização.","controle.","previsão normativa.","delegação externa."]'::jsonb, 1, 'Controle consiste em medir resultados, comparar com padrões e corrigir desvios.', 25),
  (126, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-poderes-administrativos', 'Médio', 'A prerrogativa de distribuir e escalonar funções entre órgãos e agentes, supervisionando sua atuação, decorre do poder', '["disciplinar.","regulamentar.","hierárquico.","de polícia."]'::jsonb, 2, 'O poder hierárquico permite ordenar, coordenar, delegar, avocar e fiscalizar atividades internas da administração.', 26),
  (127, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-atributos-do-ato-administrativo', 'Difícil', 'A possibilidade de a administração executar diretamente determinado ato, independentemente de autorização judicial prévia, relaciona-se ao atributo da', '["presunção de legitimidade.","autoexecutoriedade.","tipicidade.","competência."]'::jsonb, 1, 'Autoexecutoriedade é a possibilidade de execução direta de certos atos administrativos nos casos admitidos em lei.', 27),
  (128, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-anulacao-e-revogacao', 'Médio', 'Quando a administração extingue um ato válido por razões de conveniência e oportunidade, ocorre', '["cassação.","anulação.","revogação.","convalidação."]'::jsonb, 2, 'Revogação alcança ato válido, por motivo de mérito administrativo; anulação recai sobre ato ilegal.', 28),
  (129, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-principio-da-publicidade', 'Fácil', 'O princípio da publicidade, no contexto administrativo, busca assegurar principalmente', '["sigilo como regra geral dos atos públicos.","divulgação e transparência dos atos, ressalvadas hipóteses legais de restrição.","substituição do controle social por controle privado.","dispensa de motivação dos atos discricionários."]'::jsonb, 1, 'Publicidade dá transparência à atuação administrativa, admitindo sigilo apenas nas hipóteses legais.', 29),
  (130, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-agentes-publicos', 'Médio', 'Servidor que causa dano a terceiro no exercício da função pode gerar responsabilidade civil do Estado, assegurado a este o direito de', '["anistia automática.","regresso contra o agente, nos casos cabíveis.","dispensa de apuração administrativa.","renúncia obrigatória ao ressarcimento."]'::jsonb, 1, 'O Estado pode responder perante o terceiro e buscar ressarcimento do agente por ação regressiva, quando presentes os requisitos legais.', 30),
  (131, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-lei-n-14-133-2021', 'Médio', 'Na contratação pública, o termo de referência ou projeto básico deve contribuir para', '["descrição precisa do objeto e definição dos requisitos da contratação.","substituição integral do planejamento pela etapa de julgamento.","escolha livre do objeto após a assinatura contratual.","eliminação dos critérios objetivos de execução."]'::jsonb, 0, 'Esses instrumentos estruturam a contratação, delimitando objeto, requisitos, critérios e resultados esperados.', 31),
  (132, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-licitacao-e-isonomia', 'Médio', 'É incompatível com a lógica da licitação pública a cláusula que', '["estabelece critérios objetivos de habilitação.","restringe indevidamente a competitividade sem justificativa técnica.","define prazo para apresentação de propostas.","prevê sanções contratuais pelo inadimplemento."]'::jsonb, 1, 'A restrição injustificada à competição viola a isonomia e compromete a seleção da proposta mais vantajosa.', 32),
  (133, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-controle-da-administracao', 'Difícil', 'O controle exercido pela própria administração sobre seus atos, para corrigir ilegalidades e rever condutas, caracteriza o controle', '["judicial.","externo legislativo.","administrativo interno.","popular extraordinário."]'::jsonb, 2, 'Controle administrativo interno é a autotutela exercida pela própria administração sobre seus atos e agentes.', 33),
  (134, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-processo-administrativo', 'Médio', 'Em processo administrativo, a motivação do ato decisório é relevante porque', '["dispensa o contraditório.","expõe as razões da decisão e favorece controle e transparência.","substitui a competência legal do agente.","elimina a necessidade de formalização mínima."]'::jsonb, 1, 'A motivação explicita fundamentos de fato e de direito, permitindo controle administrativo, judicial e social.', 34),
  (135, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-bens-publicos', 'Fácil', 'São bens de uso comum do povo aqueles destinados', '["ao serviço interno exclusivo da repartição.","à utilização geral pela coletividade, como ruas e praças.","à alienação imediata pelo poder público.","ao patrimônio pessoal do agente público."]'::jsonb, 1, 'Bens de uso comum do povo são fruíveis pela coletividade, como ruas, praças e rios, conforme o caso.', 35),
  (136, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-principios-da-licitacao', 'Difícil', 'A exigência de critérios objetivos de julgamento nas licitações visa reduzir principalmente', '["a formalização do procedimento.","a discricionariedade arbitrária na escolha da proposta.","a publicidade dos atos administrativos.","a necessidade de planejamento da contratação."]'::jsonb, 1, 'Critérios objetivos limitam escolhas arbitrárias e reforçam isonomia, transparência e segurança jurídica.', 36),
  (137, 'portugues', 'portugues-interpretacao-de-texto', 'Médio', 'No enunciado “A digitalização agilizou o protocolo, mas exigiu treinamento da equipe”, a relação estabelecida pela conjunção “mas” é de', '["adição.","alternância.","oposição.","explicação."]'::jsonb, 2, 'A conjunção “mas” introduz ideia de contraste entre a vantagem e a exigência apontadas.', 37),
  (138, 'portugues', 'portugues-pontuacao', 'Médio', 'Assinale a alternativa em que a pontuação está de acordo com a norma-padrão.', '["Os servidores, analisaram os relatórios antes da reunião.","Quando o sistema caiu os atendimentos foram interrompidos.","A equipe revisou o documento, e enviou a versão final.","Quando o sistema caiu, os atendimentos foram interrompidos."]'::jsonb, 3, 'A oração subordinada adverbial deslocada pede vírgula: “Quando o sistema caiu, os atendimentos foram interrompidos”.', 38),
  (139, 'portugues', 'portugues-regencia-verbal', 'Difícil', 'Assinale a alternativa redigida de acordo com a norma-padrão de regência.', '["O servidor assistiu o treinamento sobre licitações.","A chefia informou aos servidores sobre a nova rotina.","A equipe preferiu mais o sistema antigo.","Os candidatos obedeceram o regulamento interno."]'::jsonb, 1, '“Informar algo a alguém” está correto. Nas demais, faltam preposição em “assistiu ao” e “obedeceram ao”, e “preferir” não admite “mais”.', 39),
  (140, 'portugues', 'portugues-crase', 'Médio', 'Assinale a alternativa em que o uso do acento indicativo de crase está correto.', '["O documento foi entregue à diretora do setor.","Os servidores retornaram à trabalhar cedo.","A reunião ocorrerá de 14h às 16h, e todos irão à pé.","O atendimento ficou sujeito à atrasos frequentes."]'::jsonb, 0, 'Há crase correta na fusão de preposição exigida pelo verbo com artigo feminino em “à diretora”.', 40),
  (141, 'portugues', 'portugues-concordancia-nominal', 'Fácil', 'Assinale a alternativa em que a concordância nominal está adequada.', '["Seguem anexo os comprovantes solicitados.","Seguem anexas as planilhas solicitadas.","É proibida entrada de pessoas sem crachá.","Muito obrigadas, disse o servidor ao cidadão."]'::jsonb, 1, '“Anexas” concorda com “planilhas”. Em “entrada de pessoas”, a expressão sem determinante costuma ficar invariável: “É proibido entrada...”.', 41),
  (142, 'portugues', 'portugues-reescrita', 'Médio', 'A reescrita que preserva o sentido de “Embora houvesse prazo, o setor não concluiu a análise” é', '["Como houvesse prazo, o setor não concluiu a análise.","Ainda que houvesse prazo, o setor não concluiu a análise.","Conforme houvesse prazo, o setor não concluiu a análise.","Porque houvesse prazo, o setor não concluiu a análise."]'::jsonb, 1, '“Embora” exprime concessão, assim como “ainda que”.', 42),
  (143, 'informatica', 'informatica-microsoft-word', 'Fácil', 'No Microsoft Word, o atalho mais usual para salvar rapidamente o documento em edição é', '["Ctrl+B.","Ctrl+S.","Ctrl+P.","Ctrl+N."]'::jsonb, 1, 'Em atalhos padrão de aplicativos, Ctrl+S salva o arquivo em edição.', 43),
  (144, 'informatica', 'informatica-seguranca-da-informacao', 'Médio', 'Uma senha considerada mais segura tende a ser aquela que', '["usa apenas sequência numérica simples e repetida.","combina letras, números e símbolos sem relação óbvia com dados pessoais.","repete o nome do usuário com o ano atual.","é compartilhada entre colegas da mesma equipe para emergências."]'::jsonb, 1, 'Senhas fortes combinam complexidade, imprevisibilidade e não devem ser compartilhadas.', 44),
  (145, 'informatica', 'informatica-internet-e-navegacao', 'Médio', 'Ao verificar se um site utiliza conexão criptografada, o usuário deve observar principalmente', '["a presença de HTTPS e do cadeado no navegador.","o tamanho da fonte da página inicial.","a quantidade de imagens no topo do site.","a existência de janelas pop-up promocionais."]'::jsonb, 0, 'HTTPS e o cadeado indicam uso de conexão criptografada, embora não eliminem outros cuidados de segurança.', 45),
  (146, 'informatica', 'informatica-compactacao-e-backup', 'Difícil', 'A compactação de arquivos é útil principalmente para', '["eliminar a necessidade de cópia de segurança.","reduzir espaço ocupado e facilitar armazenamento ou envio.","substituir softwares antivírus.","garantir, por si só, a integridade permanente dos dados."]'::jsonb, 1, 'Compactar reduz tamanho e facilita transferência, mas não substitui backup nem outras medidas de segurança.', 46),
  (147, 'raciocinio-logico', 'raciocinio-logico-equivalencia-logica', 'Difícil', 'A proposição “Se o relatório foi revisado, então não há erro material” é logicamente equivalente a', '["Se há erro material, então o relatório foi revisado.","Se há erro material, então o relatório não foi revisado.","O relatório foi revisado e há erro material.","O relatório não foi revisado ou não há erro material."]'::jsonb, 3, 'A condicional p → q é equivalente a ~p ou q. Aqui: “não foi revisado ou não há erro material”.', 47),
  (148, 'raciocinio-logico', 'raciocinio-logico-razao-e-proporcao', 'Médio', 'Em um setor, a razão entre processos concluídos e pendentes é de 5 para 3. Se há 40 processos concluídos, o número de pendentes é', '["18.","20.","24.","25."]'::jsonb, 2, 'Se 5 partes correspondem a 40, cada parte vale 8. Logo, 3 partes correspondem a 24.', 48),
  (149, 'raciocinio-logico', 'raciocinio-logico-problemas-aritmeticos', 'Fácil', 'Uma equipe arquivou 12 processos pela manhã e 18 à tarde. O total arquivado no dia foi de', '["28.","30.","32.","36."]'::jsonb, 1, '12 + 18 = 30 processos.', 49),
  (150, 'raciocinio-logico', 'raciocinio-logico-porcentagem', 'Médio', 'O orçamento de um setor passou de R$ 20.000 para R$ 23.000. O aumento percentual foi de', '["10%.","12%.","15%.","20%."]'::jsonb, 2, 'O aumento foi de R$ 3.000. Como 3.000/20.000 = 0,15, o acréscimo foi de 15%.', 50),
  (151, 'administracao-publica', 'administracao-publica-tomada-de-decisao', 'Médio', 'Ao comparar alternativas, riscos e impacto sobre o cidadão antes de escolher uma medida administrativa, o gestor pratica', '["centralização patrimonial.","processo decisório racional.","mero controle burocrático.","revogação tácita."]'::jsonb, 1, 'O processo decisório racional envolve levantamento de alternativas, critérios, riscos e consequências.', 51),
  (152, 'administracao-publica', 'administracao-publica-gestao-de-pessoas-no-setor-publico', 'Fácil', 'Uma medida coerente com gestão de pessoas é', '["ignorar feedback da equipe.","alinhar metas, capacitação e avaliação de desempenho.","substituir treinamento por ordens verbais.","eliminar comunicação interna."]'::jsonb, 1, 'Gestão de pessoas exige alinhamento de objetivos, desenvolvimento e acompanhamento de desempenho.', 52),
  (153, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-responsabilidade-civil-do-estado', 'Difícil', 'A responsabilidade objetiva do Estado, em regra, exige demonstração de', '["culpa exclusiva do agente.","dano e nexo causal.","dolo da administração.","sentença penal condenatória."]'::jsonb, 1, 'Na responsabilidade objetiva, em regra, importa comprovar dano e nexo causal entre atuação estatal e prejuízo.', 53),
  (154, 'direito-administrativo-e-licitacoes', 'direito-administrativo-e-licitacoes-processo-licitatorio', 'Médio', 'A fase de julgamento das propostas deve respeitar sobretudo', '["critérios objetivos previamente definidos.","preferências pessoais da comissão.","ajustes informais pós-abertura.","sigilo absoluto dos resultados."]'::jsonb, 0, 'A objetividade do julgamento é base da isonomia e da transparência nas licitações.', 54),
  (155, 'portugues', 'portugues-coesao-textual', 'Médio', 'Em texto administrativo, o uso de conectivos e retomadas pronominais contribui principalmente para', '["obscurecer o sentido.","coesão e progressão textual.","informalidade obrigatória.","supressão de ideias centrais."]'::jsonb, 1, 'Conectivos e retomadas criam ligação entre partes do texto, garantindo coesão.', 55),
  (156, 'portugues', 'portugues-ortografia-oficial', 'Fácil', 'Assinale a alternativa grafada corretamente segundo a norma-padrão.', '["Paralização.","Exceção.","Beneficiente.","Reinvindicação."]'::jsonb, 1, '“Exceção” segue a grafia oficial. As demais apresentam desvios ortográficos.', 56),
  (157, 'informatica', 'informatica-planilhas-e-referencias', 'Difícil', 'Em uma planilha, a referência $A$1 é classificada como', '["relativa.","mista.","absoluta.","oculta."]'::jsonb, 2, 'Com cifrão em coluna e linha, a referência permanece fixa, sendo absoluta.', 57),
  (158, 'informatica', 'informatica-seguranca-em-navegadores', 'Médio', 'Uma prática recomendada ao usar computadores compartilhados é', '["salvar senhas automaticamente em qualquer navegador.","encerrar sessão e limpar dados sensíveis ao sair.","desativar autenticação em dois fatores.","baixar extensões sem verificar origem."]'::jsonb, 1, 'Encerrar sessão e limpar dados sensíveis reduz risco de acesso indevido em máquinas compartilhadas.', 58),
  (159, 'raciocinio-logico', 'raciocinio-logico-tabela-verdade', 'Médio', 'A conjunção entre duas proposições simples será verdadeira apenas quando', '["uma delas for verdadeira.","ambas forem verdadeiras.","ambas forem falsas.","a segunda for falsa."]'::jsonb, 1, 'A conjunção p ∧ q somente é verdadeira quando as duas proposições são verdadeiras.', 59),
  (160, 'raciocinio-logico', 'raciocinio-logico-analise-combinatoria-basica', 'Difícil', 'Uma banca elaborará uma sequência com 3 questões distintas escolhidas entre 5 disponíveis. Considerando a ordem, o total de sequências possíveis é', '["10.","20.","60.","125."]'::jsonb, 2, 'Trata-se de arranjo simples: 5 × 4 × 3 = 60.', 60),
  (161, 'administracao-publica', 'administracao-publica-planejamento-governamental', 'Fácil', 'No âmbito da gestão pública, o planejamento governamental contribui para', '["alinhar objetivos, recursos e prioridades institucionais.","substituir integralmente os controles de execução.","dispensar avaliação posterior dos resultados.","eliminar a necessidade de indicadores."]'::jsonb, 0, 'Planejamento governamental organiza prioridades, recursos e metas para orientar a ação administrativa.', 61),
  (162, 'administracao-publica', 'administracao-publica-gestao-por-processos', 'Médio', 'No mapeamento de processos, a identificação de gargalos serve para', '["aumentar exigências sem relação com o resultado final.","substituir padrões por decisões casuísticas das chefias.","eliminar registros que permitam acompanhamento.","melhorar o fluxo com foco em eficiência e entrega ao usuário."]'::jsonb, 3, 'Gestão por processos prioriza fluxo, eficiência, padronização e valor ao usuário.', 62),
  (163, 'administracao-publica', 'administracao-publica-governanca-e-integridade', 'Difícil', 'Quando um órgão publica critérios, monitora riscos e define responsabilidades, ele fortalece', '["substituem a legalidade por conveniência política.","permitem decisões sem supervisão.","reduzem riscos e reforçam direção, controle e accountability.","eliminam a necessidade de prestar contas."]'::jsonb, 2, 'Governança e integridade estruturam controles, transparência e responsabilização.', 63),
  (164, 'administracao-publica', 'administracao-publica-indicadores-de-desempenho', 'Fácil', 'Indicadores de desempenho são úteis porque permitem', '["tornar desnecessária a prestação de contas.","acompanhar resultados e apoiar decisões corretivas.","dispensar metas e padrões de comparação.","substituir totalmente a análise qualitativa."]'::jsonb, 1, 'Indicadores permitem monitoramento, comparação com metas e correção de desvios.', 64),
  (165, 'administracao-publica', 'administracao-publica-lideranca-e-motivacao', 'Médio', 'Uma chefia que orienta, comunica prioridades e acompanha a equipe está atuando em', '["alinhe pessoas, comunicação e execução às metas do órgão.","elimine feedbacks para evitar conflito.","concentre todas as decisões operacionais sem diálogo.","substitua planejamento por ordens imprecisas."]'::jsonb, 0, 'Liderança envolve orientação, comunicação e alinhamento das pessoas aos objetivos institucionais.', 65),
  (166, 'administracao-publica', 'administracao-publica-qualidade-no-servico-publico', 'Difícil', 'Um efeito esperado da melhoria contínua é', '["reduzir transparência para ganhar velocidade.","eliminar toda mensuração de desempenho.","substituir treinamento por improviso.","padronizar processos e ampliar a satisfação do usuário."]'::jsonb, 3, 'Qualidade envolve padronização, melhoria contínua e foco no usuário.', 66),
  (167, 'administracao-publica', 'administracao-publica-estrutura-organizacional', 'Fácil', 'A departamentalização funcional é caracterizada por', '["eliminação de qualquer nível de coordenação.","confusão entre autoridade e responsabilidade.","agrupamento de atividades por função ou especialidade.","separação de equipes exclusivamente por interesse pessoal."]'::jsonb, 2, 'Departamentalização funcional agrupa atividades por especialidade ou função semelhante.', 67),
  (168, 'administracao-publica', 'administracao-publica-controle-administrativo', 'Médio', 'A função de controle é indispensável para', '["evitar qualquer ajuste no curso da execução.","identificar desvios e adotar medidas corretivas.","dispensar planejamento inicial.","substituir a direção de pessoas por rotinas automáticas."]'::jsonb, 1, 'Controle mede resultados, compara com padrões e orienta correções.', 68),
  (169, 'administracao-publica', 'administracao-publica-planejamento-governamental', 'Difícil', 'No ciclo gerencial, o planejamento governamental tem como efeito esperado', '["alinhar objetivos, recursos e prioridades institucionais.","substituir integralmente os controles de execução.","dispensar avaliação posterior dos resultados.","eliminar a necessidade de indicadores."]'::jsonb, 0, 'Planejamento governamental organiza prioridades, recursos e metas para orientar a ação administrativa.', 69),
  (170, 'administracao-publica', 'administracao-publica-gestao-por-processos', 'Fácil', 'Em um órgão que redesenha seu fluxo de protocolo para reduzir retrabalho, a providência mais aderente à gestão por processos é', '["aumentar exigências sem relação com o resultado final.","substituir padrões por decisões casuísticas das chefias.","eliminar registros que permitam acompanhamento.","melhorar o fluxo com foco em eficiência e entrega ao usuário."]'::jsonb, 3, 'Gestão por processos prioriza fluxo, eficiência, padronização e valor ao usuário.', 70),
  (171, 'administracao-publica', 'administracao-publica-governanca-e-integridade', 'Médio', 'A adoção de controles internos, transparência e responsabilização reforça', '["substituem a legalidade por conveniência política.","permitem decisões sem supervisão.","reduzem riscos e reforçam direção, controle e accountability.","eliminam a necessidade de prestar contas."]'::jsonb, 2, 'Governança e integridade estruturam controles, transparência e responsabilização.', 71),
  (172, 'administracao-publica', 'administracao-publica-indicadores-de-desempenho', 'Difícil', 'No setor público, um indicador bem definido deve favorecer', '["tornar desnecessária a prestação de contas.","acompanhar resultados e apoiar decisões corretivas.","dispensar metas e padrões de comparação.","substituir totalmente a análise qualitativa."]'::jsonb, 1, 'Indicadores permitem monitoramento, comparação com metas e correção de desvios.', 72),
  (173, 'administracao-publica', 'administracao-publica-lideranca-e-motivacao', 'Fácil', 'No exercício da liderança, espera-se que o gestor público', '["alinhe pessoas, comunicação e execução às metas do órgão.","elimine feedbacks para evitar conflito.","concentre todas as decisões operacionais sem diálogo.","substitua planejamento por ordens imprecisas."]'::jsonb, 0, 'Liderança envolve orientação, comunicação e alinhamento das pessoas aos objetivos institucionais.', 73),
  (174, 'administracao-publica', 'administracao-publica-qualidade-no-servico-publico', 'Médio', 'Quando o órgão revisa rotinas e corrige falhas recorrentes, está perseguindo', '["reduzir transparência para ganhar velocidade.","eliminar toda mensuração de desempenho.","substituir treinamento por improviso.","padronizar processos e ampliar a satisfação do usuário."]'::jsonb, 3, 'Qualidade envolve padronização, melhoria contínua e foco no usuário.', 74),
  (175, 'administracao-publica', 'administracao-publica-estrutura-organizacional', 'Difícil', 'A especialização por áreas técnicas costuma favorecer', '["eliminação de qualquer nível de coordenação.","confusão entre autoridade e responsabilidade.","agrupamento de atividades por função ou especialidade.","separação de equipes exclusivamente por interesse pessoal."]'::jsonb, 2, 'Departamentalização funcional agrupa atividades por especialidade ou função semelhante.', 75),
  (176, 'administracao-publica', 'administracao-publica-controle-administrativo', 'Fácil', 'No controle administrativo, a comparação entre resultado alcançado e meta prevista permite', '["evitar qualquer ajuste no curso da execução.","identificar desvios e adotar medidas corretivas.","dispensar planejamento inicial.","substituir a direção de pessoas por rotinas automáticas."]'::jsonb, 1, 'Controle mede resultados, compara com padrões e orienta correções.', 76),
